import React from 'react';
import styles from './VoucherListTableSkeleton.module.css';

export type VoucherListTableSkeletonProps = {
  rows?: number;
  testIdPrefix: string;
};

/** Mẫu B — voucher list skeleton (`voucher-list-skeleton.md`). Chỉ body rows. */
export const VoucherListTableSkeleton: React.FC<VoucherListTableSkeletonProps> = ({
  rows = 8,
  testIdPrefix,
}) => (
  <div
    className={styles.root}
    data-testid={`${testIdPrefix}-table-skeleton`}
    aria-hidden
  >
    {Array.from({ length: rows }, (_, i) => (
      <div key={i} className={styles.row}>
        <div className={styles.checkGutter} />
        <div className={styles.cells}>
          <div className={styles.cellWide} />
          <div className={styles.cell} />
          <div className={styles.cell} />
          <div className={styles.cell} />
        </div>
      </div>
    ))}
  </div>
);
